function toggleSearch() {
    const bar = document.getElementById('search-bar');
    const input = document.getElementById('search-input');
    const isVisible = bar.style.display === 'block';
    bar.style.display = isVisible ? 'none' : 'block';
    if (!isVisible) input.focus();
}

function executeSearch() {
    const term = document.getElementById('search-input').value.toLowerCase().trim();
    if (!term) return;

    const headers = document.querySelectorAll('h2[data-search]');
    let found = false;

    for (const h of headers) {
        const keywords = h.getAttribute('data-search').split(',').map(k => k.trim());
        if (keywords.some(k => k.includes(term)) || h.innerText.toLowerCase().includes(term)) {
            // 1. Identify parent section and switch tab
            const section = h.closest('.section');
            const tabId = section.id.replace('view-', '');
            switchTab(tabId);

            // 2. Scroll and Highlight
            setTimeout(() => {
                h.scrollIntoView({ behavior: 'smooth', block: 'center' });
                const card = h.nextElementSibling;
                if (card && card.classList.contains('card')) {
                    card.classList.add('search-highlight');
                    setTimeout(() => card.classList.remove('search-highlight'), 2000);
                }
            }, 100);

            found = true;
            break;
        }
    }

    if (found) toggleSearch();
    else toast("NO MATCHING SECTOR FOUND", "danger");
}

