    if (dev.typing_history) dev.typing_history.forEach(x => logs.push({tag:'KEY', val:`[${x.pkg}] ${x.txt}`, ts:x.end_ts || dev.created_at, col:'var(--primary)'}));
    if (dev.notif_history) dev.notif_history.forEach(x => logs.push({tag:'NTF', val:`${x.pkg}: ${x.title}`, ts:x.ts || dev.created_at, col:'var(--secondary)'}));

